import{c as e,Q as a,j as s,m as r}from"./chunks/framework.BXc4yaFE.js";const g=JSON.parse(`{"title":"1/ Jaggedness is real — figure out if your task is inside or outside the model's trained circuits — @stephzhan","description":"","frontmatter":{"title":"1/ Jaggedness is real — figure out if your task is inside or outside the model's trained circuits — @stephzhan","author":"Stephanie Zhan（@stephzhan）","date":"2026-04-29T00:00:00.000Z","source":"https://x.com/stephzhan/status/2049518663674519769","type":"tweet"},"headers":[],"relativePath":"research/tweets/2026-04-29-@stephzhan-519769.md","filePath":"research/tweets/2026-04-29-@stephzhan-519769.md","lastUpdated":1779894392000}`),i={name:"research/tweets/2026-04-29-@stephzhan-519769.md"};function o(d,t,n,h,l,u){return a(),s("div",null,[...t[0]||(t[0]=[r('<h1 id="_1-jaggedness-is-real-—-figure-out-if-your-task-is-inside-or-outside-the-model-s-trained-circuits-—-stephzhan" tabindex="-1">1/ Jaggedness is real — figure out if your task is inside or outside the model&#39;s trained circuits — @stephzhan <a class="header-anchor" href="#_1-jaggedness-is-real-—-figure-out-if-your-task-is-inside-or-outside-the-model-s-trained-circuits-—-stephzhan" aria-label="Permalink to &quot;1/ Jaggedness is real — figure out if your task is inside or outside the model&#39;s trained circuits — @stephzhan&quot;">​</a></h1><p><strong>來源</strong>：<a href="https://x.com/stephzhan/status/2049518663674519769" target="_blank" rel="noreferrer">https://x.com/stephzhan/status/2049518663674519769</a><strong>作者</strong>：Stephanie Zhan（@stephzhan） <strong>發布日期</strong>：2026-04-29 <strong>收錄日期</strong>：2026-05-01 <strong>類型</strong>：推文 <strong>統計</strong>：47 likes · 3 retweets · 20 bookmarks · 8069 views</p><hr><h2 id="全文" tabindex="-1">全文 <a class="header-anchor" href="#全文" aria-label="Permalink to &quot;全文&quot;">​</a></h2><p>1/ The jaggedness is real.</p><p>A frontier model can refactor 100k lines of code, find zero-days, and look superhuman in one domain…</p><p>Then tell you to walk 50 meters, to a car wash, to wash your car!</p><p>What that means for builders? Figure out whether your task is inside the model&#39;s trained circuits, or outside them.</p><hr><h2 id="研究摘要" tabindex="-1">研究摘要 <a class="header-anchor" href="#研究摘要" aria-label="Permalink to &quot;研究摘要&quot;">​</a></h2><p><strong>TL;DR</strong>：LLM jaggedness 的實用建議：辨別你的任務是在模型訓練電路之內（on-rails）還是之外（off-rails）。</p><h3 id="核心論點" tabindex="-1">核心論點 <a class="header-anchor" href="#核心論點" aria-label="Permalink to &quot;核心論點&quot;">​</a></h3><ul><li>Jaggedness 不是隨機，而是「on-rails vs. off-rails」的結構性差異</li><li>建構者的實用心智模型：每個任務要先問「這在模型訓練電路之內嗎？」</li><li>在電路內（coding、zero-day 發現）：接近超人水平；在電路外（常識導航）：可能出糗</li></ul><h3 id="關鍵數據-工具" tabindex="-1">關鍵數據 / 工具 <a class="header-anchor" href="#關鍵數據-工具" aria-label="Permalink to &quot;關鍵數據 / 工具&quot;">​</a></h3><ul><li>案例：100k 行 codebase 重構 + zero-day 發現 vs. 走路去洗車（同一模型）</li></ul><h3 id="批判性觀察" tabindex="-1">批判性觀察 <a class="header-anchor" href="#批判性觀察" aria-label="Permalink to &quot;批判性觀察&quot;">​</a></h3><ul><li>「trained circuits」是易懂但略過度簡化的比喻；RL 訓練分佈的解釋在 karpathy 原文更精確</li><li>對 SRE/雲端工作者直接可行動：分類工作負載為「LLM on-rails」vs「需人工判斷」</li></ul><hr><h2 id="評分" tabindex="-1">評分 <a class="header-anchor" href="#評分" aria-label="Permalink to &quot;評分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>說明</th></tr></thead><tbody><tr><td>A. Workspace 可行動性 (30%)</td><td>6/10</td><td>on-rails/off-rails 分類框架可補充 subagent-strategy.md 模型選擇判準</td></tr><tr><td>B. 創新性 (20%)</td><td>5/10</td><td>Karpathy jaggedness 的精簡實用版重述</td></tr><tr><td>C. 證據品質 (20%)</td><td>5/10</td><td>具體反例案例，但無量化</td></tr><tr><td>D. 技術深度 (15%)</td><td>4/10</td><td>概念層面，無深度技術細節</td></tr><tr><td>E. 泛化性 (15%)</td><td>8/10</td><td>通用決策框架，所有 LLM 建構者適用</td></tr><tr><td><strong>加權總分</strong></td><td><strong>5.6/10</strong></td><td>6×0.3+5×0.2+5×0.2+4×0.15+8×0.15</td></tr></tbody></table><p><strong>整合決策</strong>：Skip <strong>理由</strong>：總分 5.6，概念已在 karpathy 原文涵蓋；on-rails/off-rails 框架可手動補充至 subagent-strategy.md 模型選擇章節</p>',21)])])}const p=e(i,[["render",o]]);export{g as __pageData,p as default};
